import { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { getVehicleById, updateVehicle } from "../../api/vehicleApi";

export default function EditVehicle() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [vehicle, setVehicle] = useState(null);

  const vehicleTypes = ["SUV", "Sedan", "Hatchback", "Truck", "Van", "Coupe"];
  const statuses = ["available", "reserved", "sold"];

  useEffect(() => {
    getVehicleById(id)
      .then((res) => setVehicle(res.data))
      .catch(() => {
        alert("Vehicle not found");
        navigate("/vehicles");
      });
  }, [id, navigate]);

  if (!vehicle) return <p style={{ padding: 20 }}>Loading...</p>;

  const handleChange = (e) => {
    setVehicle({ ...vehicle, [e.target.name]: e.target.value });
  };

  const submit = async (e) => {
    e.preventDefault();

    const currentYear = new Date().getFullYear();
    if (Number(vehicle.year) > currentYear) {
      alert(`Year cannot be in the future (max ${currentYear})`);
      return;
    }

    try {
      await updateVehicle(id, vehicle);
      alert("Vehicle updated!");
      navigate("/vehicles");
    } catch (err) {
      alert(err.response?.data?.message || "Update failed");
    }
  };

  return (
    <div style={{ padding: 20, maxWidth: 520 }}>
      <h2>Edit Vehicle</h2>

      <form onSubmit={submit}>
        <input
          name="brand"
          placeholder="Brand"
          value={vehicle.brand || ""}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
          required
        />

        <select
          name="type"
          value={vehicle.type || ""}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
          required
        >
          <option value="">Select Vehicle Type</option>
          {vehicleTypes.map((t) => (
            <option key={t} value={t}>{t}</option>
          ))}
        </select>

        <input
          name="year"
          type="number"
          placeholder="Year"
          value={vehicle.year || ""}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
          required
        />

        <input
          name="price"
          type="number"
          placeholder="Price"
          value={vehicle.price || ""}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
          required
        />

        <select
          name="status"
          value={vehicle.status || "available"}
          onChange={handleChange}
          style={{ width: "100%", padding: 10, marginBottom: 10 }}
        >
          {statuses.map((s) => (
            <option key={s} value={s}>{s}</option>
          ))}
        </select>

        <button style={{ padding: "10px 14px" }}>Save Changes</button>
      </form>
    </div>
  );
}
